// frontend/src/components/SearchForm.js
import React, { useState } from 'react';

const SearchForm = () => {
  const [selectedDistrict, setSelectedDistrict] = useState('');
  const [selectedTaluka, setSelectedTaluka] = useState('');
  const [selectedVillage, setSelectedVillage] = useState('');
  const [surveyNumber, setSurveyNumber] = useState('');
  const [mobile, setMobile] = useState('');
  const [language, setLanguage] = useState('mr_in');
  const [captcha, setCaptcha] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    alert(`
      District: ${selectedDistrict}
      Taluka: ${selectedTaluka}
      Village: ${selectedVillage}
      Survey Number: ${surveyNumber}
      Mobile: ${mobile}
      Language: ${language}
      Captcha: ${captcha}
    `);
  };

  const handleReset = () => {
    setSelectedDistrict('');
    setSelectedTaluka('');
    setSelectedVillage('');
    setSurveyNumber('');
    setMobile('');
    setLanguage('mr_in');
    setCaptcha('');
  };

  return (
    <form
      onSubmit={handleSubmit}
      style={{
        width: '70%',
        float: 'right',
        padding: '20px',
        backgroundColor: '#f8f9fa',
        borderRadius: '8px'
      }}
    >
      <h3 style={{ textAlign: 'center', marginBottom: '20px' }}>७/१२ माहिती (7/12 Details)</h3>

      {/* District */}
      <div style={{ marginBottom: '15px' }}>
        <label>जिल्हा(District)</label>
        <select
          value={selectedDistrict}
          onChange={e => setSelectedDistrict(e.target.value)}
          className="form-control"
        >
          <option value="">--निवडा--</option>
          <option value="5">अकोला</option>
          <option value="7">अमरावती</option>
          <option value="4">बुलडाणा</option>
          <option value="14">यवतमाळ</option>
          <option value="6">वाशिम</option>
          <option value="29">धाराशिव</option>
          <option value="19">छत्रपती संभाजीनगर</option>
          <option value="18">जालना</option>
          <option value="15">नांदेड</option>
          <option value="17">परभणी</option>
          <option value="27">बीड</option>
          <option value="28">लातूर</option>
          <option value="16">हिंगोली</option>
          <option value="21">ठाणे</option>
          <option value="36">पालघर</option>
          <option value="22">मंबई उपनगर</option>
          <option value="32">रत्नागिरी</option>
          <option value="24">रायगड</option>
          <option value="33">सिंधुदुर्ग</option>
          <option value="12">गडचिरोली</option>
          <option value="11">गोंदिया</option>
          <option value="13">चंद्रपूर</option>
          <option value="9">नागपूर</option>
          <option value="10">भंडारा</option>
          <option value="8">वर्धा</option>
          <option value="26">अहिल्यानगर</option>
          <option value="3">जळगाव</option>
          <option value="2">धुळे</option>
          <option value="1">नंदुरबार</option>
          <option value="20">नाशिक</option>
          <option value="34">कोल्हापूर</option>
          <option value="25">पुणे</option>
          <option value="35">सांगली</option>
          <option value="31">सातारा</option>
          <option value="30">सोलापूर</option>
        </select>
      </div>

      {/* Taluka */}
      <div style={{ marginBottom: '15px' }}>
        <label>तालुका(Taluka)</label>
        <select
          value={selectedTaluka}
          onChange={e => setSelectedTaluka(e.target.value)}
          className="form-control"
        >
          <option value="">--निवडा--</option>
          <option value="1">अकोला</option>
          <option value="2">अमरावती</option>
          <option value="3">बुलडाणा</option>
          <option value="4">यवतमाळ</option>
          <option value="5">वाशिम</option>
          <option value="6">धाराशिव</option>
          <option value="7">छत्रपती संभाजीनगर</option>
          <option value="8">जालना</option>
          <option value="9">नांदेड</option>
          <option value="10">परभणी</option>
          <option value="11">बीड</option>
          <option value="12">लातूर</option>
          <option value="13">हिंगोली</option>
          <option value="14">ठाणे</option>
          <option value="15">पालघर</option>
          <option value="16">मंबई उपनगर</option>
          <option value="17">रत्नागिरी</option>
          <option value="18">रायगड</option>
          <option value="19">सिंधुदुर्ग</option>
          <option value="20">गडचिरोली</option>
          <option value="21">गोंदिया</option>
          <option value="22">चंद्रपूर</option>
          <option value="23">नागपूर</option>
          <option value="24">भंडारा</option>
          <option value="25">वर्धा</option>
          <option value="26">अहिल्यानगर</option>
          <option value="27">जळगाव</option>
          <option value="28">धुळे</option>
          <option value="29">नंदुरबार</option>
          <option value="30">नाशिक</option>
          <option value="31">कोल्हापूर</option>
          <option value="32">पुणे</option>
          <option value="33">सांगली</option>
          <option value="34">सातारा</option>
          <option value="35">सोलापूर</option>
        </select>
      </div>

      {/* Village */}
      <div style={{ marginBottom: '15px' }}>
        <label>गाव(Village)</label>
        <select
          value={selectedVillage}
          onChange={e => setSelectedVillage(e.target.value)}
          className="form-control"
        >
          <option value="">--निवडा--</option>
          <option value="V1">Village 1</option>
          <option value="V2">Village 2</option>
          <option value="V3">Village 3</option>
          <option value="V4">Village 4</option>
          <option value="V5">Village 5</option>
          {/* You can add all villages as needed */}
        </select>
      </div>

      {/* Survey number, Mobile, Language, Captcha */}
      <div style={{ marginBottom: '15px' }}>
        <label>सर्वे नंबर(भाग 1)(Survey Number Part 1)</label>
        <input
          type="text"
          value={surveyNumber}
          onChange={e => setSurveyNumber(e.target.value)}
          className="form-control"
        />
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>मोबाईल(Mobile)</label>
        <input
          type="text"
          value={mobile}
          onChange={e => setMobile(e.target.value)}
          className="form-control"
        />
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>भाषा निवडा(Select Language)</label>
        <select
          value={language}
          onChange={e => setLanguage(e.target.value)}
          className="form-control"
        >
          <option value="mr_in">Marathi</option>
          <option value="en_in">English</option>
          <option value="hi_in">Hindi</option>
        </select>
      </div>

      <div style={{ marginBottom: '15px' }}>
        <label>सांकेतिक क्रमांक(Captcha)</label>
        <input
          type="text"
          value={captcha}
          onChange={e => setCaptcha(e.target.value)}
          className="form-control"
        />
      </div>

      {/* Submit & Reset */}
      <div style={{ textAlign: 'center', marginTop: '20px' }}>
        <button type="submit" className="btn btn-info" style={{ marginRight: '10px' }}>Submit</button>
        <button type="button" className="btn btn-secondary" onClick={handleReset}>Reset</button>
      </div>
    </form>
  );
};

export default SearchForm;
